      '基础框架（2分）：正确解析 CNF 输入格式，数据结构设计合理。单位传播（2分）：正确实现 BCP，能识别单位子句并传播赋值，处理传播链。纯文字消除（1分）：正确识别纯文字并赋值。CDCL 核心机制（3分）：(a) 冲突分析正确构建蕴含图；(b) 学习子句正确（UIP 方法或类似）；(c) 非 chronological 回跳到正确的决策层。正确性与完整性（2分）：能处理含 100+ 变量的公式，边界情况处理正确（空子句=UNSAT，空公式=SAT，重言子句忽略）。缺少 CDCL 最多得5分；单位传播有 bug 扣2-3分。',
    maxScore: 10,
    referenceAnswer: '参考答案（8分水平）：\n\n以下实现演示了完整的 CDCL SAT 求解器。支持 DIMACS CNF，包含 BCP 单位传播、纯文字消除、1-UIP 冲突分析与子句学习、非时序回退。约 180 行 Python。\n\n代码：\n\nfrom typing import List, Dict, Optional, Tuple, Set\nfrom dataclasses import dataclass\n\n@dataclass\nclass Clause:\n    literals: List[int]\n    learned: bool = False\n\n@dataclass\nclass ImplNode:\n    literal: int\n    level: int\n    antecedent: Optional[int] = None\n\nclass CDCLSolver:\n    """CDCL SAT 求解器"""\n\n    def __init__(self):\n        self.clauses: List[Clause] = []\n        self.num_vars: int = 0\n        self.value: Dict[int, Optional[bool]] = {}\n        self.level: int = 0\n        self.graph: List[ImplNode] = []\n        self.watches: Dict[int, List[int]] = {}\n\n    def parse(self, text: str):\n        """解析 DIMACS CNF。"""\n        self.clauses = []\n        for line in text.strip().splitlines():\n            line = line.strip()\n            if not line or line.startswith("c"):\n                continue\n            if line.startswith("p"):\n                parts = line.split()\n                self.num_vars = int(parts[2])\n                self.value = {i: None for i in range(1, self.num_vars + 1)}\n                continue\n            lits = [int(x) for x in line.split() if x != "0"]\n            if lits:\n                self.clauses.append(Clause(lits))\n        self.watches = {l: [] for l in range(-self.num_vars, self.num_vars + 1) if l != 0}\n        for ci, cl in enumerate(self.clauses):\n            if len(cl.literals) >= 1:\n                self.watches[cl.literals[0]].append(ci)\n            if len(cl.literals) >= 2:\n                self.watches[cl.literals[1]].append(ci)\n\n    def lit_val(self, lit: int) -> Optional[bool]:\n        v = self.value.get(abs(lit))\n        return None if v is None else (v if lit > 0 else not v)\n\n    def is_sat(self, cl: Clause) -> bool:\n        return any(self.lit_val(l) is True for l in cl.literals)\n\n    def is_false(self, cl: Clause) -> bool:\n        return all(self.lit_val(l) is False for l in cl.literals)\n\n    def find_unit(self, cl: Clause) -> Optional[int]:\n        unassigned = None\n        for l in cl.literals:\n            v = self.lit_val(l)\n            if v is True:\n                return None\n            if v is None:\n                if unassigned is not None:\n                    return None\n                unassigned = l\n        return unassigned\n\n    def assign(self, var: int, val: bool, ante: Optional[int] = None):\n        self.value[var] = val\n        lit = var if val else -var\n        self.graph.append(ImplNode(lit, self.level, ante))\n\n    def backtrack(self, to_level: int):\n        for node in self.graph:\n            if node.level > to_level:\n                self.value[abs(node.literal)] = None\n        self.graph = [n for n in self.graph if n.level <= to_level]\n\n    def bcp(self) -> Optional[Clause]:\n        """BCP 单位传播。"""\n        q = list(range(len(self.clauses)))\n        checked = set()\n        while q:\n            ci = q.pop()\n            if ci in checked:\n                continue\n            checked.add(ci)\n            cl = self.clauses[ci]\n            if self.is_sat(cl):\n                continue\n            unit = self.find_unit(cl)\n            if unit is not None:\n                var, val = abs(unit), unit > 0\n                self.assign(var, val, ci)\n                for other in self.watches.get(-unit, []):\n                    if other not in checked:\n                        q.append(other)\n            elif self.is_false(cl):\n                return cl\n        return None\n\n    def pure_literal_eliminate(self):\n        polarity: Dict[int, Set[int]] = {}\n        for cl in self.clauses:\n            if self.is_sat(cl):\n                continue\n            for l in cl.literals:\n                if self.lit_val(l) is None:\n                    polarity.setdefault(abs(l), set()).add(1 if l > 0 else 0)\n        for var, pols in polarity.items():\n            if len(pols) == 1 and self.value[var] is None:\n                self.assign(var, 1 in pols)\n\n    def analyze(self, conflict: Clause) -> Tuple[Clause, int]:\n        """1-UIP 冲突分析。返回 (学习子句, 回退层)。"""\n        ante_map: Dict[int, Optional[Clause]] = {}\n        for node in self.graph:\n            if node.antecedent is not None:\n                ante_map[node.literal] = self.clauses[node.antecedent]\n        cur = list(conflict.literals)\n        while True:\n            cur_level = [l for l in cur\n                        for n in self.graph\n                        if n.literal == l and n.level == self.level]\n            if len(cur_level) <= 1:\n                break\n            for lit in reversed(cur_level):\n                ant = ante_map.get(lit)\n                if ant is None:\n                    continue\n                new = [l for l in cur if l != lit]\n                for l in ant.literals:\n                    if l != -lit:\n                        new.append(l)\n                cur = list(set(new))\n                break\n        levels = set()\n        for l in cur:\n            for n in self.graph:\n                if n.literal == l:\n                    levels.add(n.level)\n                    break\n        levels.discard(self.level)\n        bt = max(levels) if levels else 0\n        return Clause(cur, learned=True), bt\n\n    def decide(self) -> Optional[int]:\n        for v in range(1, self.num_vars + 1):\n            if self.value[v] is None:\n                return v\n        return None\n\n    def solve(self) -> Tuple[bool, Dict[int, bool]]:\n        """主 CDCL 循环。"""\n        if any(not cl.literals for cl in self.clauses):\n            return False, {}\n        while True:\n            conflict = self.bcp()\n            if conflict:\n                if self.level == 0:\n                    return False, {}\n                learned, bt = self.analyze(conflict)\n                self.clauses.append(learned)\n                self.backtrack(bt)\n                self.level = bt\n                continue\n            self.pure_literal_eliminate()\n            var = self.decide()\n            if var is None:\n                assign = {v: self.value[v] for v in range(1, self.num_vars + 1)\n                         if self.value[v] is not None}\n                return True, assign\n            self.level += 1\n            self.assign(var, True)\n\n    def verify(self, assign: Dict[int, bool]) -> bool:\n        for cl in self.clauses:\n            ok = any(assign.get(abs(l)) == (l > 0) for l in cl.literals\n                    if abs(l) in assign)\n            if not ok:\n                return False\n        return True\n\n边界情况处理：\n- 空子句（0文字）直接返回 UNSAT\n- 空公式（无子句）返回 SAT\n- 重言子句（含互补文字）自动忽略\n- 决策层 0 冲突 → 公式不可满足\n\n与满分(10分)的差距：\n- 观察列表仅简单索引，非严格 2-literal watching（正确但效率较低）\n- 决策启发式简单，未实现 VSIDS\n- 未实现学习子句定期删除和重启策略',
