    maxScore: 10,
    referenceAnswer: '参考答案（8分水平）：\n\nMichael-Scott 无锁并发队列 (C++17)。使用 128-bit tagged pointer 解决 ABA 问题，hazard pointer 管理内存回收。\n\n代码：\n\n#include <atomic>\n#include <cstdint>\n#include <vector>\n#include <thread>\n#include <cassert>\n\n// === Tagged Pointer（解决 ABA）===\n// 指针 + 64-bit 计数器打包为 128-bit，CAS 同时比较两者\nstruct TaggedPtr { void* ptr; uint64_t tag; };\n\nbool CAS128(std::atomic<TaggedPtr>& tgt, TaggedPtr& exp, TaggedPtr des) {\n    __int128 d = *reinterpret_cast<__int128*>(&des);\n    __int128* e = reinterpret_cast<__int128*>(&exp);\n    return __atomic_compare_exchange_16(&tgt, e, &d, false,\n        __ATOMIC_SEQ_CST, __ATOMIC_SEQ_CST);\n}\n// 注：若平台不支持 128-bit CAS，需降级为 per-bucket 互斥锁\n\n// === Hazard Pointer（简化版，每线程最多保护 2 个指针）===\nconstexpr int MAX_HP = 2, MAX_THREADS = 64;\nthread_local int tl_hp0 = 0, tl_hp1 = 0;\nstd::atomic<void*> hp_list[MAX_THREADS][MAX_HP];\nstd::vector<void*> retired[MAX_THREADS];\nint next_tid = 0;\nint get_tid() { thread_local int id = next_tid++; return id; }\n\nvoid hp_protect(int slot, void* p) { hp_list[get_tid()][slot].store(p); }\nvoid hp_clear(int slot) { hp_list[get_tid()][slot].store(nullptr); }\n\nvoid retire_ptr(void* p) {\n    int tid = get_tid();\n    retired[tid].push_back(p);\n    if (retired[tid].size() > 64) {\n        auto& r = retired[tid];\n        for (auto it = r.begin(); it != r.end(); ) {\n            bool busy = false;\n            for (int t = 0; t < MAX_THREADS && !busy; ++t)\n                for (int h = 0; h < MAX_HP; ++h)\n                    if (hp_list[t][h].load() == *it) { busy = true; break; }\n            if (!busy) { ::operator delete(*it); it = r.erase(it); }\n            else ++it;\n        }\n    }\n}\n\n// === Michael-Scott Lock-Free Queue ===\ntemplate<typename T>\nclass LockFreeQueue {\n    struct Node {\n        T value;\n        std::atomic<TaggedPtr> next;\n        Node(const T& v) : value(v), next(TaggedPtr{nullptr, 0}) {}\n    };\n\n    std::atomic<TaggedPtr> head;   // 哨兵节点\n    std::atomic<TaggedPtr> tail;\n\npublic:\n    LockFreeQueue() {\n        Node* d = new Node(T{});\n        head.store(TaggedPtr{d, 0});\n        tail.store(TaggedPtr{d, 0});\n    }\n\n    void enqueue(const T& value) {\n        Node* node = new Node(value);\n        while (true) {\n            TaggedPtr last = tail.load();\n            Node* lp = static_cast<Node*>(last.ptr);\n            TaggedPtr next = lp->next.load();\n\n            if (last.ptr != tail.load().ptr) continue;\n\n            if (next.ptr == nullptr) {\n                TaggedPtr nd = {node, next.tag + 1};\n                if (CAS128(lp->next, next, nd)) {\n                    TaggedPtr nt = {node, last.tag + 1};\n                    CAS128(tail, last, nt);  // 推进 tail（可失败）\n                    return;\n                }\n            } else {\n                // 帮助推进 tail\n                TaggedPtr nt = {next.ptr, last.tag + 1};\n                CAS128(tail, last, nt);\n            }\n        }\n    }\n\n    bool dequeue(T& result) {\n        while (true) {\n            TaggedPtr first = head.load();\n            Node* fp = static_cast<Node*>(first.ptr);\n            TaggedPtr last = tail.load();\n            TaggedPtr next_val = fp->next.load();\n            Node* np = static_cast<Node*>(next_val.ptr);\n\n            // Hazard pointer 保护 next 节点\n            hp_protect(0, np);\n            if (fp->next.load().ptr != np) { hp_clear(0); continue; }\n\n            if (first.ptr != head.load().ptr) { hp_clear(0); continue; }\n\n            if (fp == static_cast<Node*>(last.ptr)) {\n                if (np == nullptr) { hp_clear(0); return false; }\n                TaggedPtr nt = {np, last.tag + 1};\n                CAS128(tail, last, nt);\n                hp_clear(0);\n                continue;\n            }\n\n            result = np->value;\n            TaggedPtr nh = {np, first.tag + 1};\n            if (CAS128(head, first, nh)) {\n                hp_clear(0);\n                retire_ptr(fp);  // 延迟回收旧哨兵\n                return true;\n            }\n            hp_clear(0);\n        }\n    }\n};\n\n// === 多线程测试（4 生产者 + 4 消费者）===\nvoid test_mt() {\n    LockFreeQueue<int> q;\n    const int N = 10000;\n    std::atomic<long long> psum{0}, csum{0};\n\n    auto prod = [&]() {\n        for (int i = 0; i < N; ++i) {\n            int v = rand() % 100;\n            psum += v; q.enqueue(v);\n        }\n    };\n    auto cons = [&]() {\n        for (int i = 0; i < N; ++i) {\n            int v;\n            while (!q.dequeue(v)) {}  // 忙等，非阻塞语义\n            csum += v;\n        }\n    };\n\n    std::vector<std::thread> th;\n    for (int i = 0; i < 4; ++i) { th.emplace_back(prod); th.emplace_back(cons); }\n    for (auto& t : th) t.join();\n    int v; while (q.dequeue(v)) csum += v;  // 清空\n    assert(psum == csum);  // 线性一致性检查\n}\n\n关键设计说明：\n- ABA 解决：TaggedPtr 中的 tag 每次 CAS 递增，即便节点地址被复用，(ptr, tag) 组合也不同，CAS 必然失败\n- 帮助推进：enqueue 第一步链接节点，第二步推进 tail。若线程在两步之间暂停，其他线程检测到 next.ptr != nullptr，帮助推进 tail\n- 内存回收：hazard pointer 方案。dequeue 在读取 next->value 前通过 hp_protect 保护 next 指针；retire_ptr 延迟释放未被任何线程 HP 保护的节点\n\n与满分(10分)的差距：\n- retire_ptr 扫描为 O(N*T)，非生产级；实际应用 epoch-based reclamation 或完整 HP 方案\n- 未实现节点池复用（free list），频繁 new/delete 影响性能\n- 128-bit CAS 依赖平台支持，未提供 64-bit 降级方案',
